const req = $input.first().json;

const headers = req.headers || {};
const update  = req.body   || req;

const secret = process.env.TELEGRAM_WEBHOOK_SECRET || '';
if (secret) {
  const received = headers['x-telegram-bot-api-secret-token'] || '';
  if (received !== secret) {
    return [{ json: { isLike:false, isDislike:false, isStats:false, isQuestion:false, blocked:true } }];
  }
}

const cq  = update?.callback_query;
const msg = update?.message;
const OWNER = process.env.TELEGRAM_CHAT_ID || '';

if (msg && typeof msg.text === 'string') {
  const t = msg.text.trim();
  const chatId = String(msg.chat?.id || '');

  if (t.startsWith('/stats')) {
    return [{ json: { isLike:false, isDislike:false, isStats:true, isQuestion:false,
      chatId, articleId:0, callbackQueryId:'' } }];
  }
  // любой непустой текст не-команда от владельца = запрос на разбор
  if (t && !t.startsWith('/') && (!OWNER || chatId === OWNER)) {
    return [{ json: { isLike:false, isDislike:false, isStats:false, isQuestion:true,
      text:t, chatId, articleId:0, callbackQueryId:'' } }];
  }
  return [{ json: { isLike:false, isDislike:false, isStats:false, isQuestion:false, chatId } }];
}

if (!cq) return [{ json: { isLike:false, isDislike:false, isStats:false, isQuestion:false } }];

const parts = (cq.data || '').split(':');
const action    = parts[0];
const articleId = parseInt(parts[1]);
const isLike    = action === 'like'    && articleId > 0;
const isDislike = action === 'dislike' && articleId > 0;

return [{ json: {
  isLike, isDislike, isStats:false, isQuestion:false,
  articleId,
  callbackQueryId: cq.id,
  chatId:  String(cq.message?.chat?.id || ''),
  messageId: cq.message?.message_id
}}];

const parseData = $('Parse Callback').first().json;
const { articleId, isLike, isDislike } = parseData;
const BASE = process.env.SUPABASE_URL;
const KEY  = process.env.SUPABASE_ANON_KEY;
const h    = { apikey: KEY, Authorization: 'Bearer '+KEY };

const [artRes, profRes] = await Promise.all([
  $helpers.httpRequest({ method:'GET', url: BASE+'/rest/v1/articles?id=eq.'+articleId+'&select=*', headers: h }),
  $helpers.httpRequest({ method:'GET', url: BASE+'/rest/v1/interest_profile?id=eq.1', headers: h })
]);

const article = Array.isArray(artRes)  ? artRes[0]  : artRes;
const profile = Array.isArray(profRes) ? profRes[0] : profRes;

if (!article) return [{ json: { error: 'article_not_found', articleId } }];

return [{ json: {
  articleId,
  isLike,
  isDislike,
  article,
  profile: profile || { sources:{}, keywords:{}, total_feedbacks:0 }
}}];

const { article, profile, articleId, isLike, isDislike } = $input.first().json;
const ALPHA  = 0.2;
const signal = isLike ? 1.0 : 0.0;

const sources  = { ...profile.sources  };
const keywords = { ...profile.keywords };

if (article.source) {
  sources[article.source] = ALPHA * signal + (1-ALPHA) * (sources[article.source] || 0.5);
}
for (const kw of (article.keywords || [])) {
  keywords[kw] = ALPHA * signal + (1-ALPHA) * (keywords[kw] || 0.5);
}

return [{ json: {
  articleId,
  isLike,
  article,
  updatedProfile: {
    sources, keywords,
    total_feedbacks: (profile.total_feedbacks || 0) + 1,
    updated_at: new Date().toISOString()
  }
}}];

const { articleId, isLike, updatedProfile } = $input.first().json;
const BASE = process.env.SUPABASE_URL;
const KEY  = process.env.SUPABASE_ANON_KEY;
const h    = { apikey:KEY, Authorization:'Bearer '+KEY, 'Content-Type':'application/json' };

const ops = [
  $helpers.httpRequest({
    method:'PATCH',
    url: BASE+'/rest/v1/interest_profile?id=eq.1',
    headers: { ...h, Prefer:'return=minimal' },
    body: JSON.stringify(updatedProfile)
  })
];

if (isLike) {
  ops.push($helpers.httpRequest({
    method:'POST',
    url: BASE+'/rest/v1/feedback',
    headers: { ...h, Prefer:'return=minimal' },
    body: JSON.stringify({ article_id: articleId })
  }));
}

await Promise.all(ops);

return [{ json: { ok: true, articleId, action: isLike ? 'like' : 'dislike', total: updatedProfile.total_feedbacks } }];

const { chatId } = $('Parse Callback').first().json;
const BASE = process.env.SUPABASE_URL;
const KEY  = process.env.SUPABASE_ANON_KEY;
const h    = { apikey: KEY, Authorization: 'Bearer '+KEY };

const profRes = await $helpers.httpRequest({
  method: 'GET',
  url: BASE + '/rest/v1/interest_profile?id=eq.1',
  headers: h
});

const profile  = (Array.isArray(profRes) ? profRes[0] : profRes) || {};
const sources  = profile.sources  || {};
const keywords = profile.keywords || {};
const total    = profile.total_feedbacks || 0;

const pct = w => (w * 100).toFixed(0) + '%';

const topSrc = Object.entries(sources)
  .sort((a,b) => b[1]-a[1]).slice(0,5)
  .map(([s,w]) => '  ' + s + '  ' + pct(w)).join(String.fromCharCode(10))
  || '  —';

const topKw = Object.entries(keywords)
  .sort((a,b) => b[1]-a[1]).slice(0,10)
  .map(([k,w]) => '  #' + k + '  ' + pct(w)).join(String.fromCharCode(10))
  || '  —';

const NL = String.fromCharCode(10);
const statsText = [
  '📊 Твой профиль интересов',
  '',
  'Всего оценок (👍+👎): ' + total,
  '',
  '🌐 Топ источники:',
  topSrc,
  '',
  '🔑 Топ темы:',
  topKw
].join(NL);

return [{ json: { statsText, chatId } }];

const { text, chatId } = $('Parse Callback').first().json;
const BASE = process.env.SUPABASE_URL;
const KEY  = process.env.SUPABASE_ANON_KEY;
const sh   = { apikey:KEY, Authorization:'Bearer '+KEY };

try {
  async function loadDay(day){
    const r = await $helpers.httpRequest({
      method:'GET',
      url: BASE+'/rest/v1/articles?digest_id=eq.'+day+'&order=score.desc',
      headers: sh
    });
    return Array.isArray(r) ? r : [];
  }

  const today = new Date().toISOString().slice(0,10);
  let arts = await loadDay(today);
  if (!arts.length) {
    const y = new Date(Date.now()-864e5).toISOString().slice(0,10);
    arts = await loadDay(y);
  }
  if (!arts.length) {
    return [{ json: { answer: 'Пока нет статей для разбора — дайджест ещё не приходил сегодня.', chatId } }];
  }

  // какая статья: номер / порядковое слово / совпадение по словам заголовка
  const lower = text.toLowerCase();
  const ord = { 'перв':1,'втор':2,'трет':3,'четверт':4,'пят':5,'шест':6,'седьм':7,'восьм':8,'девят':9,'десят':10 };
  let idx = null;
  const mnum = lower.match(/\b(\d{1,2})\b/);
  if (mnum) idx = parseInt(mnum[1]);
  else { for (const k in ord) { if (lower.includes(k)) { idx = ord[k]; break; } } }

  let target = null;
  if (idx && arts[idx-1]) target = arts[idx-1];
  if (!target) {
    const stop = new Set(['про','расскажи','подробнее','что','это','about','tell','more','новость','статью','статья','можешь']);
    const qt = new Set(lower.split(/[^a-zа-яё0-9]+/i).filter(w => w.length > 3 && !stop.has(w)));
    let best=null, bestScore=0;
    for (const a of arts) {
      const tt = String(a.title||'').toLowerCase();
      let s = 0; for (const w of qt) if (tt.includes(w)) s++;
      if (s > bestScore) { bestScore = s; best = a; }
    }
    target = bestScore > 0 ? best : arts[0];
  }

  // полный текст статьи
  let full = '';
  try {
    const r = await $helpers.httpRequest({
      method:'GET', url: target.link, timeout:8000,
      headers:{ 'User-Agent':'Mozilla/5.0 (compatible; NewsDigestBot/1.0)' }
    });
    const s = (typeof r==='string') ? r : (r && r.body ? r.body : '');
    full = s.replace(/<script[\s\S]*?<\/script>/gi,' ')
            .replace(/<style[\s\S]*?<\/style>/gi,' ')
            .replace(/<[^>]+>/g,' ')
            .replace(/&[a-z]+;/gi,' ')
            .replace(/\s+/g,' ').trim().slice(0,6000);
  } catch(e) {}

  const material = (full && full.length > 200) ? full : String(target.title||'');
  const prompt = 'Сделай подробный разбор этой новости на русском языке. Структура: 1) Что произошло (2-3 предложения). 2) Почему это важно. 3) Контекст и детали. 4) Что это значит на практике. Пиши просто и по делу.' +
    String.fromCharCode(10)+String.fromCharCode(10) + 'Заголовок: ' + target.title +
    String.fromCharCode(10)+String.fromCharCode(10) + 'Текст:' + String.fromCharCode(10) + material;

  const lr = await $helpers.httpRequest({
    method:'POST', url:'https://openrouter.ai/api/v1/chat/completions',
    headers:{ Authorization:'Bearer '+process.env.OPENROUTER_API_KEY, 'Content-Type':'application/json' },
    body: JSON.stringify({
      model: process.env.OPENROUTER_MODEL || 'google/gemini-2.5-flash',
      messages: [{ role:'user', content: prompt }]
    })
  });
  const parsed = (typeof lr==='string') ? JSON.parse(lr) : lr;
  let body = parsed?.choices?.[0]?.message?.content || 'Не удалось разобрать статью.';

  const NL = String.fromCharCode(10);
  const answer = '🔍 ' + target.title + NL+NL + body.slice(0,3500) + NL+NL + '→ ' + target.link;
  return [{ json: { answer, chatId } }];
} catch (e) {
  return [{ json: { answer: 'Не получилось сделать разбор — попробуй ещё раз чуть позже.', chatId } }];
}

const key = process.env.EMBEDDINGS_API_KEY;
const isLike = $('Parse Callback').first().json.isLike;
const ld = $('Load Data').first().json;
const article = ld && ld.article;

if (!key || !isLike || !article) {
  return [{ json: { taste: 'skipped' } }];
}

try {
  const url   = process.env.EMBEDDINGS_URL   || 'https://api.openai.com/v1/embeddings';
  const model = process.env.EMBEDDINGS_MODEL || 'text-embedding-3-small';
  const BASE  = process.env.SUPABASE_URL;
  const SKEY  = process.env.SUPABASE_ANON_KEY;
  const sh    = { apikey:SKEY, Authorization:'Bearer '+SKEY, 'Content-Type':'application/json' };

  const text = (String(article.title||'')+'. '+(article.keywords||[]).join(', ')).slice(0,800);

  const er = await $helpers.httpRequest({
    method:'POST', url,
    headers:{ Authorization:'Bearer '+key, 'Content-Type':'application/json' },
    body: JSON.stringify({ model, input: text })
  });
  const ed  = (typeof er==='string') ? JSON.parse(er) : er;
  const emb = ed.data[0].embedding;

  const tr = await $helpers.httpRequest({
    method:'GET', url: BASE+'/rest/v1/taste_vector?id=eq.1',
    headers:{ apikey:SKEY, Authorization:'Bearer '+SKEY }
  });
  const t = Array.isArray(tr) ? tr[0] : tr;
  const old = (t && Array.isArray(t.vector)) ? t.vector : null;
  const n   = (t && t.n) || 0;

  const ALPHA = 0.2;
  let nv;
  if (old && old.length === emb.length) nv = old.map((v,i) => ALPHA*emb[i] + (1-ALPHA)*v);
  else nv = emb.slice();

  await $helpers.httpRequest({
    method:'PATCH', url: BASE+'/rest/v1/taste_vector?id=eq.1',
    headers:{ ...sh, Prefer:'return=minimal' },
    body: JSON.stringify({ vector: nv, n: n+1, updated_at: new Date().toISOString() })
  });

  return [{ json: { taste: 'updated', n: n+1 } }];
} catch (e) {
  return [{ json: { taste: 'error', message: String(e && e.message || e) } }];
}
